/* static/js/jalali-datepicker.min.js */
(function() {
    function jalaliLength(y, m) {
        if (m <= 6) return 31;
        if (m <= 11) return 30;
        return isLeapJalali(y) ? 30 : 29;
    }
    function isLeapJalali(y) {
        var matches = [1, 5, 9, 13, 17, 22, 26, 30], mod = y % 33;
        for (var i = 0; i < matches.length; i++) if (mod === matches[i]) return true;
        return false;
    }
    function jalaliToGregorian(jy, jm, jd) {
        jy += 1595; var days = -355668 + (365 * jy) + (Math.floor(jy / 33) * 8) + Math.floor(((jy % 33) + 3) / 4) + jd + ((jm < 7) ? (jm - 1) * 31 : ((jm - 7) * 30) + 186);
        var gy = 400 * Math.floor(days / 146097); days %= 146097;
        if (days > 36524) { gy += 100 * Math.floor(--days / 36524); days %= 36524; if (days >= 365) days++; }
        gy += 4 * Math.floor(days / 1461); days %= 1461;
        if (days > 365) { gy += Math.floor((days - 1) / 365); days = (days - 1) % 365; }
        var gd = days + 1;
        var sal = [0, 31, ((gy % 4 === 0 && gy % 100 !== 0) || gy % 400 === 0) ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
        var gm; for (gm = 1; gm < 13 && gd > sal[gm]; gm++) gd -= sal[gm];
        return [gy, gm, gd];
    }
    function gregorianToJalali(gy, gm, gd) {
        var sal = [0, 31, ((gy % 4 === 0 && gy % 100 !== 0) || gy % 400 === 0) ? 29 : 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
        var days = gd; for (var i = 1; i < gm; i++) days += sal[i];
        var gy2 = gy - 1600, days2 = days + 365 * gy2 + Math.floor((gy2 + 3) / 4) - Math.floor((gy2 + 99) / 100) + Math.floor((gy2 + 399) / 400) - 80;
        var jy = 979 + 33 * Math.floor(days2 / 12053); days2 %= 12053;
        jy += 4 * Math.floor(days2 / 1461); days2 %= 1461;
        if (days2 > 365) { jy += Math.floor((days2 - 1) / 365); days2 = (days2 - 1) % 365; }
        var jm = (days2 < 186) ? 1 + Math.floor(days2 / 31) : 7 + Math.floor((days2 - 186) / 30);
        var jd = 1 + ((days2 < 186) ? days2 % 31 : (days2 - 186) % 30);
        return [jy, jm, jd];
    }
    function getWeekdayOfFirstDay(jy, jm) {
        var g = jalaliToGregorian(jy, jm, 1);
        var d = new Date(g[0], g[1] - 1, g[2]);
        return (d.getDay() + 1) % 7;
    }

    var activeInput = null, pickerEl = null, currentYear, currentMonth;
    var monthsNames = ["فروردین","اردیبهشت","خرداد","تیر","مرداد","شهریور","مهر","آبان","آذر","دی","بهمن","اسفند"];
    var daysNames = ["ش", "ی", "د", "س", "چ", "پ", "ج"];

    function initPicker() {
        if (pickerEl) return;
        pickerEl = document.createElement("div");
        pickerEl.id = "jdp-container";
        pickerEl.style.cssText = "position:absolute; background:#181825; border:1px solid #313244; border-radius:12px; padding:16px; font-family:inherit; direction:rtl; z-index:999999; display:none; width:280px; box-shadow:0 20px 25px -5px rgba(0,0,0,0.5); color:#cdd6f4;";
        document.body.appendChild(pickerEl);
        pickerEl.addEventListener("click", function(e) { e.stopPropagation(); });
    }

    function render() {
        var html = '<div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:14px;">';
        html += '<button type="button" id="jdp-prev" style="background:#252538; border:1px solid #3f3f56; color:#a6adc8; border-radius:6px; padding:4px 10px; cursor:pointer; font-size:12px; font-weight:bold;">◀ ماه قبل</button>';
        html += '<div style="font-weight:bold; color:#bac2de; font-size:14px;">' + monthsNames[currentMonth - 1] + ' ' + currentYear + '</div>';
        html += '<button type="button" id="jdp-next" style="background:#252538; border:1px solid #3f3f56; color:#a6adc8; border-radius:6px; padding:4px 10px; cursor:pointer; font-size:12px; font-weight:bold;">ماه بعد ▶</button>';
        html += '</div>';

        html += '<div style="display:grid; grid-template-columns:repeat(7, 1fr); text-align:center; font-size:11px; color:#89b4fa; margin-bottom:8px; font-weight:bold;">';
        for(var i=0; i<7; i++) html += '<div>' + daysNames[i] + '</div>';
        html += '</div>';

        html += '<div style="display:grid; grid-template-columns:repeat(7, 1fr); gap:6px; text-align:center;">';
        var firstDayWk = getWeekdayOfFirstDay(currentYear, currentMonth);
        var len = jalaliLength(currentYear, currentMonth);

        for(var b=0; b<firstDayWk; b++) html += '<div></div>';

        for(var d=1; d<=len; d++) {
            html += '<div class="jdp-day-cell" data-day="' + d + '" style="padding:6px 0; cursor:pointer; border-radius:6px; font-size:13px; font-family:inherit; color:#cdd6f4;">' + d + '</div>';
        }
        html += '</div>';
        
        html += '<button type="button" id="jdp-today-btn" style="width:100%; margin-top:14px; background:#45475a; border:none; color:#cdd6f4; padding:8px; border-radius:6px; cursor:pointer; font-size:12px; font-family:inherit; font-weight:bold;">انتخاب امروز</button>';

        pickerEl.innerHTML = html;

        pickerEl.querySelector("#jdp-prev").onclick = function() {
            currentMonth--; if (currentMonth < 1) { currentMonth = 12; currentYear--; } render();
        };
        pickerEl.querySelector("#jdp-next").onclick = function() {
            currentMonth++; if (currentMonth > 12) { currentMonth = 1; currentYear++; } render();
        };
        pickerEl.querySelector("#jdp-today-btn").onclick = function() {
            var today = gregorianToJalali(new Date().getFullYear(), new Date().getMonth() + 1, new Date().getDate());
            selectDate(today[0], today[1], today[2]);
        };

        pickerEl.querySelectorAll(".jdp-day-cell").forEach(function(c) {
            c.onmouseover = function() { c.style.background = "#313244"; };
            c.onmouseout = function() { c.style.background = "none"; };
            c.onclick = function() {
                selectDate(currentYear, currentMonth, parseInt(c.getAttribute("data-day")));
            };
        });
    }

    function selectDate(y, m, d) {
        if (!activeInput) return;
        var mm = m < 10 ? "0" + m : m, dd = d < 10 ? "0" + d : d;
        activeInput.value = y + "/" + mm + "/" + dd;
        activeInput.dispatchEvent(new Event('change', { bubbles: true }));
        hide();
    }

    function show(input) {
        activeInput = input; initPicker();
        var p = input.value.split("/");
        if (p.length === 3) {
            currentYear = parseInt(p[0]); currentMonth = parseInt(p[1]);
        } else {
            var today = gregorianToJalali(new Date().getFullYear(), new Date().getMonth() + 1, new Date().getDate());
            currentYear = today[0]; currentMonth = today[1];
        }
        render();
        var rect = input.getBoundingClientRect();
        pickerEl.style.top = (rect.bottom + window.scrollY + 6) + "px";
        pickerEl.style.left = (rect.left + window.scrollX) + "px";
        pickerEl.style.display = "block";
    }

    function hide() { if (pickerEl) pickerEl.style.display = "none"; activeInput = null; }

    window.jalaliDatepicker = {
        start: function() {
            document.querySelectorAll("[data-jdp]").forEach(function(input) {
                if (input.dataset.jdpBound) return; input.dataset.jdpBound = "true";
                input.addEventListener("focus", function() { show(input); });
                input.addEventListener("click", function(e) { e.stopPropagation(); show(input); });
            });
            document.addEventListener("click", function() { hide(); });
        }
    };
})();